<template><div class="page-wrap"><section class="page-hero"><div><span class="eyebrow">ACCOUNT SECURITY</span><h1>管理员个人中心</h1><p>查看账号信息并维护管理中心登录安全</p></div><div class="shield"><el-icon><Lock /></el-icon></div></section><section class="profile-grid"><div class="identity-card"><div class="profile-avatar">{{initial}}</div><h2>{{auth.admin?.name||'系统管理员'}}</h2><p>云脑诊疗平台管理员</p><el-tag type="success" effect="light" round><el-icon><CircleCheckFilled/></el-icon> 身份已认证</el-tag><div class="identity-line"></div><div class="info-row"><span>登录账号</span><strong>{{auth.admin?.username}}</strong></div><div class="info-row"><span>角色权限</span><strong>超级管理员</strong></div><div class="info-row"><span>创建时间</span><strong>{{formatTime(auth.admin?.createTime)}}</strong></div></div><div class="security-card"><div class="card-head"><span>SECURITY SETTINGS</span><h2>修改登录密码</h2><p>建议定期修改密码，保护管理平台数据安全</p></div><el-form ref="formRef" :model="form" :rules="rules" label-position="top" class="password-form"><el-form-item label="原密码" prop="oldPassword"><el-input v-model="form.oldPassword" type="password" show-password size="large" :prefix-icon="Lock" placeholder="请输入当前密码"/></el-form-item><el-form-item label="新密码" prop="newPassword"><el-input v-model="form.newPassword" type="password" show-password size="large" :prefix-icon="Key" placeholder="至少6位字符"/></el-form-item><el-form-item label="确认新密码" prop="confirmPassword"><el-input v-model="form.confirmPassword" type="password" show-password size="large" :prefix-icon="Key" placeholder="请再次输入新密码"/></el-form-item><el-alert title="密码修改后，当前登录状态仍然有效；下次登录请使用新密码。" type="info" :closable="false"/><div class="action"><el-button type="primary" class="primary-btn" size="large" :loading="saving" @click="save">确认修改密码</el-button></div></el-form></div></section></div></template>
<script setup lang="ts">
import{computed,reactive,ref}from'vue';import{ElMessage,type FormInstance,type FormRules}from'element-plus';import{Lock,Key}from'@element-plus/icons-vue';import{changeAdminPassword}from'@/api/admin';import{useAuthStore}from'@/stores/auth';const auth=useAuthStore(),saving=ref(false),formRef=ref<FormInstance>();const form=reactive({oldPassword:'',newPassword:'',confirmPassword:''});const initial=computed(()=>(auth.admin?.name||'管').slice(0,1));const formatTime=(v?:string)=>v?new Date(v).toLocaleString('zh-CN'):'--';const validateConfirm=(_r:unknown,v:string,cb:(e?:Error)=>void)=>v===form.newPassword?cb():cb(new Error('两次输入的新密码不一致'));const rules:FormRules={oldPassword:[{required:true,message:'请输入原密码',trigger:'blur'}],newPassword:[{required:true,message:'请输入新密码',trigger:'blur'},{min:6,message:'新密码至少6位',trigger:'blur'}],confirmPassword:[{required:true,message:'请确认新密码',trigger:'blur'},{validator:validateConfirm,trigger:'blur'}]};const save=async()=>{if(!await formRef.value?.validate().catch(()=>false))return;saving.value=true;try{await changeAdminPassword(form.oldPassword,form.newPassword);Object.assign(form,{oldPassword:'',newPassword:'',confirmPassword:''});ElMessage.success('密码修改成功')}finally{saving.value=false}}
</script>
<style scoped>.shield{position:relative;z-index:2;width:62px;height:62px;display:flex;align-items:center;justify-content:center;margin-right:20px;border:1px solid rgba(255,255,255,.18);border-radius:18px;background:rgba(255,255,255,.11);font-size:28px}.profile-grid{display:grid;grid-template-columns:320px 1fr;gap:18px;margin-top:18px}.identity-card,.security-card{border:1px solid #e1ebed;border-radius:20px;background:#fff;box-shadow:0 9px 28px rgba(26,67,81,.06)}.identity-card{padding:30px 25px;text-align:center}.profile-avatar{width:88px;height:88px;display:flex;align-items:center;justify-content:center;margin:0 auto;border:6px solid #ecf8f5;border-radius:28px;background:linear-gradient(145deg,#d7f0ec,#b5dfd9);color:#087f84;font-size:34px;font-weight:800}.identity-card h2{margin:16px 0 5px}.identity-card>p{margin-bottom:13px;color:#82969d;font-size:12px}.identity-line{height:1px;margin:24px 0 13px;background:#edf2f3}.info-row{display:flex;justify-content:space-between;padding:10px 2px;font-size:12px}.info-row span{color:#8b9ca2}.info-row strong{color:#405b65}.security-card{padding:29px 32px}.card-head{padding-bottom:23px;border-bottom:1px solid #edf2f3}.card-head span{color:#118d82;font-size:10px;font-weight:800;letter-spacing:2px}.card-head h2{margin:6px 0;font-size:23px}.card-head p{color:#8a9ca3;font-size:12px}.password-form{max-width:600px;padding-top:24px}.password-form .el-form-item{margin-bottom:20px}.password-form :deep(.el-form-item__label){color:#536e78;font-weight:650}.password-form :deep(.el-input__wrapper){min-height:44px;border-radius:11px}.password-form .el-alert{margin-top:5px}.action{display:flex;justify-content:flex-end;margin-top:22px}.action .el-button{min-width:170px}</style>
